document.addEventListener("DOMContentLoaded",function(){const n=document.querySelector("[data-home-featured-deck]");if(!n)return;const e=Array.from(n.querySelectorAll("[data-home-featured-item]"));if(!e.length)return;const s="home-featured-next-index";let t=0;try{const n=parseInt(window.localStorage.getItem(s),10);!Number.isNaN(n)&&n>=0&&(t=n%e.length),window.localStorage.setItem(s,String((t+1)%e.length))}catch{t=0}e.forEach(function(e,n){e.hidden=n!==t})})